# Unit Tests for `retry` Function

```python
import pytest
from unittest.mock import MagicMock


# Assuming the retry function is in a module called `utils`
# from utils import retry

def retry(fn, max_attempts: int = 3):
    for attempt in range(max_attempts):
        try:
            return fn()
        except Exception:
            if attempt == max_attempts - 1:
                raise


class TestRetryHappyPath:
    """Tests for successful execution scenarios."""

    def test_succeeds_on_first_attempt(self):
        """Function should return immediately on success."""
        fn = MagicMock(return_value="success")
        result = retry(fn)
        assert result == "success"
        assert fn.call_count == 1

    def test_succeeds_on_second_attempt(self):
        """Function should retry and return when it eventually succeeds."""
        fn = MagicMock(side_effect=[ValueError("fail"), "success"])
        result = retry(fn)
        assert result == "success"
        assert fn.call_count == 2

    def test_succeeds_on_last_attempt(self):
        """Function should succeed if last attempt works."""
        fn = MagicMock(side_effect=[
            ValueError("fail1"),
            ValueError("fail2"),
            "success"
        ])
        result = retry(fn, max_attempts=3)
        assert result == "success"
        assert fn.call_count == 3

    def test_returns_none_value(self):
        """Function should correctly return None if fn returns None."""
        fn = MagicMock(return_value=None)
        result = retry(fn)
        assert result is None
        assert fn.call_count == 1

    def test_returns_falsy_values(self):
        """Function should correctly return falsy values like 0, '', []."""
        for falsy in [0, "", [], False, {}]:
            fn = MagicMock(return_value=falsy)
            result = retry(fn)
            assert result == falsy

    def test_returns_complex_object(self):
        """Function should correctly return complex objects."""
        expected = {"key": "value", "list": [1, 2, 3]}
        fn = MagicMock(return_value=expected)
        result = retry(fn)
        assert result == expected


class TestRetryEdgeCases:
    """Tests for edge cases."""

    def test_max_attempts_one_success(self):
        """With max_attempts=1, should still work for success."""
        fn = MagicMock(return_value="ok")
        result = retry(fn, max_attempts=1)
        assert result == "ok"
        assert fn.call_count == 1

    def test_max_attempts_one_failure(self):
        """With max_attempts=1, exception should be raised immediately."""
        fn = MagicMock(side_effect=ValueError("fail"))
        with pytest.raises(ValueError, match="fail"):
            retry(fn, max_attempts=1)
        assert fn.call_count == 1

    def test_max_attempts_zero_returns_none(self):
        """With max_attempts=0, the loop never runs, function returns None."""
        fn = MagicMock(return_value="ok")
        result = retry(fn, max_attempts=0)
        assert result is None
        assert fn.call_count == 0

    def test_max_attempts_negative_returns_none(self):
        """With negative max_attempts, the loop never runs."""
        fn = MagicMock(return_value="ok")
        result = retry(fn, max_attempts=-1)
        assert result is None
        assert fn.call_count == 0

    def test_default_max_attempts_is_three(self):
        """Default max_attempts should be 3."""
        fn = MagicMock(side_effect=ValueError("fail"))
        with pytest.raises(ValueError):
            retry(fn)
        assert fn.call_count == 3

    def test_high_max_attempts(self):
        """Should work with a large number of retries."""
        fn = MagicMock(side_effect=[ValueError("fail")] * 9 + ["success"])
        result = retry(fn, max_attempts=10)
        assert result == "success"
        assert fn.call_count == 10

    def test_lambda_function(self):
        """Should work with a lambda."""
        result = retry(lambda: 42)
        assert result == 42

    def test_function_with_side_effects(self):
        """Should work with function that has side effects."""
        counter = {"value": 0}

        def increment():
            counter["value"] += 1
            if counter["value"] < 3:
                raise RuntimeError("not yet")
            return counter["value"]

        result = retry(increment, max_attempts=5)
        assert result == 3
        assert counter["value"] == 3


